class Solution:
    def diagonalSum(self, mat):
        n = len(mat)
        total = 0
        seen = set()
        for i in range(n):
            for j in range(n):
                if i == j or i + j == n - 1:
                    if (i, j) not in seen:
                        seen.add((i, j))
                        total += mat[i][j]
        return total

