var diagonalSum = function(mat) {
    const n = mat.length;
    let total = 0;
    for (let i = 0; i < n; i++) {
        total += mat[i][i];
        const j = n - 1 - i;
        if (j !== i) {
            total += mat[i][j];
        }
    }
    return total;
};
